// Self-review and secure implementation
class SecureDApp {
    constructor() {
        this.provider = null;
        this.signer = null;
        this.contract = null;
        this.contractAddress = null;
        this.abi = null;
        this.pendingTransactions = new Map();
    }

    async connectWallet() {
        if (typeof window.ethereum !== 'undefined') {
            try {
                const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
                if (accounts.length === 0) {
                    throw new Error('No accounts found');
                }
                this.provider = new ethers.providers.Web3Provider(window.ethereum);
                this.signer = this.provider.getSigner();
                return true;
            } catch (error) {
                console.error('Wallet connection failed:', error);
                throw new Error('Failed to connect wallet: ' + error.message);
            }
        } else {
            throw new Error('MetaMask not detected');
        }
    }

    async initializeContract(contractAddress, abi) {
        if (!contractAddress || !abi) {
            throw new Error('Contract address and ABI are required');
        }

        this.contractAddress = contractAddress;
        this.abi = abi;
        
        if (!this.signer) {
            throw new Error('Wallet not connected');
        }

        try {
            this.contract = new ethers.Contract(contractAddress, abi, this.signer);
            return true;
        } catch (error) {
            console.error('Contract initialization failed:', error);
            throw new Error('Failed to initialize contract: ' + error.message);
        }
    }

    async executeTransaction(methodName, params, value = 0, gasLimit = null) {
        if (!this.contract || !this.signer) {
            throw new Error('Contract not initialized or wallet not connected');
        }

        if (!methodName) {
            throw new Error('Method name is required');
        }

        // Validate parameters
        if (!Array.isArray(params)) {
            throw new Error('Parameters must be an array');
        }

        try {
            const txParams = {
                value: ethers.utils.parseEther(value.toString())
            };

            if (gasLimit) {
                txParams.gasLimit = gasLimit;
            }

            const tx = await this.contract[methodName](...params, txParams);
            
            // Store transaction for tracking
            const txHash = tx.hash;
            this.pendingTransactions.set(txHash, {
                status: 'pending',
                timestamp: Date.now(),
                method: methodName,
                params: params
            });

            const receipt = await tx.wait();
            
            // Update transaction status
            this.pendingTransactions.set(txHash, {
                ...this.pendingTransactions.get(txHash),
                status: 'confirmed',
                receipt: receipt
            });

            return receipt;
        } catch (error) {
            console.error('Transaction failed:', error);
            
            // Clean up pending transaction on failure
            if (error.transactionHash) {
                this.pendingTransactions.delete(error.transactionHash);
            }
            
            throw new Error('Transaction failed: ' + error.message);
        }
    }

    async getTransactionReceipt(txHash) {
        if (!this.provider) {
            throw new Error('Provider not initialized');
        }
        
        if (!txHash) {
            throw new Error('Transaction hash is required');
        }

        try {
            const receipt = await this.provider.getTransactionReceipt(txHash);
            return receipt;
        } catch (error) {
            console.error('Failed to get transaction receipt:', error);
            throw new Error('Failed to retrieve transaction receipt: ' + error.message);
        }
    }

    async getTransactionStatus(txHash) {
        if (!this.pendingTransactions.has(txHash)) {
            return null;
        }
        return this.pendingTransactions.get(txHash);
    }

    async estimateGas(methodName, params, value = 0) {
        if (!this.contract) {
            throw new Error('Contract not initialized');
        }

        try {
            const estimate = await this.contract.estimateGas[methodName](...params, {
                value: ethers.utils.parseEther(value.toString())
            });
            return estimate;
        } catch (error) {
            console.error('Gas estimation failed:', error);
            throw new Error('Gas estimation failed: ' + error.message);
        }
    }

    async validateContractAddress(address) {
        if (!address) {
            return false;
        }
        return ethers.utils.isAddress(address);
    }

    async validateMethodExists(methodName) {
        if (!this.contract) {
            return false;
        }
        return typeof this.contract[methodName] === 'function';
    }
}